local function CGKMprns(data, order, key)
    local merged = {}

    -- susun ulang
    for i = 1, #order do
        merged[order[i]] = data[i]
    end

    local result = ""
    local index = 1

    for i = 1, #merged do
        for j = 1, #merged[i] do
            local k = string.byte(key, ((index - 1) % #key) + 1)
            result = result .. string.char(bit32.bxor(merged[i][j], k))
            index = index + 1
        end
    end

    return result
end

